228	///////////////////////////////////////////////////////////////////////////////////////////////////
229	
230	/// Naive reference GEMM computation.
231	__global__ void ReferenceGemm_kernel(
232	  int M,
233	  int N,
234	  int K,
235	  float alpha,
236	  float const *A,
237	  int lda,
238	  float const *B,
239	  int ldb,
240	  float beta,
241	  float *C,
242	  int ldc) {
243	
244	  int i = threadIdx.x + blockIdx.x * blockDim.x;
245	  int j = threadIdx.y + blockIdx.y * blockDim.y;
246	
247	  if (i < M && j < N) {
248	    float accumulator = 0;
249	
250	    for (int k = 0; k < K; ++k) {
251	      accumulator += A[i + k * lda] * B[k + j * ldb];
252	    }
253	
254	    C[i + j * ldc] = alpha * accumulator + beta * C[i + j * ldc];
255	  }
256	}
257	
258	/// Reference GEMM computation.
259	cudaError_t ReferenceGemm(
260	  int M,
261	  int N,
262	  int K,
263	  float alpha,
264	  float const *A,
265	  int lda,
266	  float const *B,
267	  int ldb,
268	  float beta,
269	  float *C,
270	  int ldc) {
271	
272	  dim3 block(16, 16);
273	  dim3 grid(
274	    (M + block.x - 1) / block.x,
275	    (N + block.y - 1) / block.y
276	  );
277	
278	  ReferenceGemm_kernel<<< grid, block >>>(M, N, K, alpha, A, lda, B, ldb, beta, C, ldc);
279	
280	  return cudaGetLastError();
281	}
