284	
285	/// Allocate several matrices in GPU device memory and call a single-precision
286	/// CUTLASS GEMM kernel.
287	cudaError_t TestCutlassGemm(int M, int N, int K, float alpha, float beta) {
288	  cudaError_t result;
289	
290	  //
291	  // Define several matrices to be used as operands to GEMM kernels.
292	  //
293	
294	  // Compute leading dimensions for each matrix.
295	  int lda = M;
296	  int ldb = K;
297	  int ldc = M;
298	
299	  // Compute size in bytes of the C matrix.
300	  size_t sizeof_C = sizeof(float) * ldc * N;
301	
302	  // Define pointers to matrices in GPU device memory.
303	  float *A;
304	  float *B;
305	  float *C_cutlass;
306	  float *C_reference;
307	
308	  //
309	  // Allocate matrices in GPU device memory with arbitrary seeds.
310	  //
311	
312	  result = AllocateMatrix(&A, M, K, 0);
313	
314	  if (result !=  cudaSuccess) {
315	    return result;
316	  }
317	
318	  result = AllocateMatrix(&B, K, N, 17);
319	
320	  if (result !=  cudaSuccess) {
321	    cudaFree(A);
322	    return result;
323	  }
324	
325	  result = AllocateMatrix(&C_cutlass, M, N, 101);
326	
327	  if (result != cudaSuccess) {
328	    cudaFree(A);
329	    cudaFree(B);
330	    return result;
331	  }
332	
333	  result = AllocateMatrix(&C_reference, M, N, 101);
334	
335	  if (result != cudaSuccess) {
336	    cudaFree(A);
337	    cudaFree(B);
338	    cudaFree(C_cutlass);
339	    return result;
340	  }
341	
342	  result = cudaMemcpy(C_reference, C_cutlass, sizeof_C, cudaMemcpyDeviceToDevice);
343	
344	  if (result != cudaSuccess) {
345	    std::cerr << "Failed to copy C_cutlass matrix to C_reference: "
346	      << cudaGetErrorString(result) << std::endl;
347	
348	    cudaFree(C_reference);
349	    cudaFree(C_cutlass);
350	    cudaFree(B);
351	    cudaFree(A);
352	
353	    return result;
354	  }
355	
356	  //
357	  // Launch CUTLASS GEMM.
358	  //
359	
360	  result = CutlassSgemmNN(M, N, K, alpha, A, lda, B, ldb, beta, C_cutlass, ldc);
361	
362	  if (result != cudaSuccess) {
363	    std::cerr << "CUTLASS GEMM kernel failed: "
364	      << cudaGetErrorString(result) << std::endl;
365	
366	    cudaFree(C_reference);
367	    cudaFree(C_cutlass);
368	    cudaFree(B);
369	    cudaFree(A);
370	
371	    return result;
372	  }
373	
374	  //
375	  // Verify.
376	  //
377	
378	  // Launch reference GEMM
379	  result = ReferenceGemm(M, N, K, alpha, A, lda, B, ldb, beta, C_reference, ldc);
380	
381	  if (result != cudaSuccess) {
382	    std::cerr << "Reference GEMM kernel failed: "
383	      << cudaGetErrorString(result) << std::endl;
384	
385	    cudaFree(C_reference);
386	    cudaFree(C_cutlass);
387	    cudaFree(B);
388	    cudaFree(A);
389	
390	    return result;
391	  }
392	
393	  // Copy to host and verify equivalence.
394	  std::vector<float> host_cutlass(ldc * N, 0);
395	  std::vector<float> host_reference(ldc * N, 0);
396	
397	  result = cudaMemcpy(host_cutlass.data(), C_cutlass, sizeof_C, cudaMemcpyDeviceToHost);
398	
399	  if (result != cudaSuccess) {
400	    std::cerr << "Failed to copy CUTLASS GEMM results: "
401	      << cudaGetErrorString(result) << std::endl;
402	
403	    cudaFree(C_reference);
404	    cudaFree(C_cutlass);
405	    cudaFree(B);
406	    cudaFree(A);
407	
408	    return result;
409	  }
410	
411	  result = cudaMemcpy(host_reference.data(), C_reference, sizeof_C, cudaMemcpyDeviceToHost);
412	
413	  if (result != cudaSuccess) {
414	    std::cerr << "Failed to copy Reference GEMM results: "
415	      << cudaGetErrorString(result) << std::endl;
416	
417	    cudaFree(C_reference);
418	    cudaFree(C_cutlass);
419	    cudaFree(B);
420	    cudaFree(A);
421	
422	    return result;
423	  }
424	
425	  //
426	  // Free device memory allocations.
427	  //
428	
429	  cudaFree(C_reference);
430	  cudaFree(C_cutlass);
431	  cudaFree(B);
432	  cudaFree(A);
433	
434	  //
435	  // Test for bit equivalence of results.
436	  //
437	
438	  if (host_cutlass != host_reference) {
439	    std::cerr << "CUTLASS results incorrect." << std::endl;
440	
441	    return cudaErrorUnknown;
442	  }
443	
444	  return cudaSuccess;
445	}
