449	/// Entry point to basic_gemm example.
450	//
451	// usage:
452	//
453	//   00_basic_gemm <M> <N> <K> <alpha> <beta>
454	//
455	int main(int argc, const char *arg[]) {
456	
457	  //
458	  // Parse the command line to obtain GEMM dimensions and scalar values.
459	  //
460	
461	  // GEMM problem dimensions.
462	  int problem[3] = { 128, 128, 128 };
463	
464	  for (int i = 1; i < argc && i < 4; ++i) {
465	    std::stringstream ss(arg[i]);
466	    ss >> problem[i - 1];
467	  }
468	
469	  // Scalars used for linear scaling the result of the matrix product.
470	  float scalars[2] = { 1, 0 };
471	
472	  for (int i = 4; i < argc && i < 6; ++i) {
473	    std::stringstream ss(arg[i]);
474	    ss >> scalars[i - 4];
475	  }
476	
477	  //
478	  // Run the CUTLASS GEMM test.
479	  //
480	
481	  cudaError_t result = TestCutlassGemm(
482	    problem[0],     // GEMM M dimension
483	    problem[1],     // GEMM N dimension
484	    problem[2],     // GEMM K dimension
485	    scalars[0],     // alpha
486	    scalars[1]      // beta
487	  );
488	
489	  if (result == cudaSuccess) {
490	    std::cout << "Passed." << std::endl;
491	  }
492	
493	  // Exit.
494	  return result == cudaSuccess ? 0 : -1;
495	}
